import React, { useState } from "react";

function App() {
  // Card image paths — make sure the image files are exactly named and in public/cards/
  const cardImages = [
    "/cards/1_bereshitA.png",
    "/cards/1B_bereshitB.png",
    "/cards/har_habayit_1a.png",
    "/cards/har_habayit_1b.png",
    "/cards/tzadik_card.png",
    "/cards/Sotah_47.png",
  ];

  const [currentCardIndex, setCurrentCardIndex] = useState(0);

  const handlePrevious = () => {
    setCurrentCardIndex((prevIndex) =>
      (prevIndex - 1 + cardImages.length) % cardImages.length
    );
  };

  const handleNext = () => {
    setCurrentCardIndex((prevIndex) =>
      (prevIndex + 1) % cardImages.length
    );
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.heading}>Parsha Card Viewer</h1>

      <img
        src={cardImages[currentCardIndex]}
        alt="Card"
        style={styles.image}
      />

      <div style={styles.buttonContainer}>
        <button onClick={handlePrevious} style={styles.button}>Previous</button>
        <button onClick={handleNext} style={{ ...styles.button, marginLeft: "10px" }}>
          Next
        </button>
      </div>

      <p style={styles.counter}>
        Showing card {currentCardIndex + 1} of {cardImages.length}
      </p>
    </div>
  );
}

const styles = {
  container: {
    textAlign: "center",
    padding: "40px",
    fontFamily: "Arial, sans-serif",
    backgroundColor: "#f0f2f5",
    minHeight: "100vh",
  },
  heading: {
    marginBottom: "30px",
  },
  image: {
    width: "300px",
    height: "auto",
    border: "2px solid #333",
    borderRadius: "12px",
    boxShadow: "0 4px 10px rgba(0,0,0,0.2)",
    marginBottom: "20px",
  },
  buttonContainer: {
    marginTop: "10px",
  },
  button: {
    padding: "10px 20px",
    fontSize: "16px",
    borderRadius: "8px",
    border: "none",
    backgroundColor: "#007bff",
    color: "white",
    cursor: "pointer",
  },
  counter: {
    marginTop: "20px",
    fontSize: "14px",
    color: "#555",
  },
};

export default App;
